This Rust code implements a connection pool. Find the bug, explain when it manifests, and suggest improvements:

```rust
use std::collections::VecDeque;
use std::time::{Duration, Instant};

struct Conn;
impl Conn {
    fn new() -> Self { Conn }
}

struct ConnPool {
    idle: VecDeque<(Conn, Instant)>,
    max_idle: usize,
    max_age: Duration,
}

impl ConnPool {
    fn new(max_idle: usize, max_age: Duration) -> Self {
        Self {
            idle: VecDeque::new(),
            max_idle,
            max_age,
        }
    }

    fn get(&mut self) -> Conn {
        while let Some((conn, created)) = self.idle.pop_front() {
            if created.elapsed() < self.max_age {
                return conn;
            }
        }
        Conn::new()
    }

    fn put(&mut self, conn: Conn) {
        if self.idle.len() < self.max_idle {
            self.idle.push_back((conn, Instant::now()));
        }
    }
}
